// Handler for serving files from the uploads directory
async fn serve_upload(path: web::Path<String>) -> Result<NamedFile> {
    let filename = path.into_inner();
    let file_path = PathBuf::from(UPLOADS_DIR).join(&filename);

    // Security check: Prevent directory traversal attacks.
    // Canonicalize both the uploads directory and the requested file path.
    // Then, ensure the requested file path is indeed a child of the uploads directory.
    let canonical_uploads_dir = Path::new(UPLOADS_DIR)
        .canonicalize()
        .map_err(|e| {
            actix_web::error::ErrorInternalServerError(format!("Failed to canonicalize uploads directory: {}", e))
        })?;

    let canonical_file_path = file_path
        .canonicalize()
        .map_err(|e| {
            // If the file doesn't exist, canonicalize will return NotFound.
            if e.kind() == std::io::ErrorKind::NotFound {
                actix_web::error::ErrorNotFound(format!("File not found: {}", filename))
            } else {
                actix_web::error::ErrorInternalServerError(format!("Failed to access file: {}", e))
            }
        })?;

    if !canonical_file_path.starts_with(&canonical_uploads_dir) {
        return Err(actix_web::error::ErrorBadRequest("Invalid file path specified (directory traversal attempt detected)."));
    }

    // `NamedFile::open` automatically handles:
    // - Checking if the file exists.
    // - Setting appropriate HTTP headers (Content-Type based on extension, Content-Disposition, Last-Modified, ETag).
    // - Handling 404 if the file is not found (after our canonicalize check).
    // - Handling range requests for partial content.
    NamedFile::open(file_path).map_err(|e| {
        // This error handling is mostly for cases where `NamedFile::open` might fail
        // after `canonicalize` succeeded (e.g., file permissions changed, or it's not a regular file).
        if e.kind() == std::io::ErrorKind::NotFound {
            actix_web::error::ErrorNotFound(format!("File not found: {}", filename))
        } else {
            actix_web::error::ErrorInternalServerError(format!("Failed to read file: {}", e))
        }
    })
}

